INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2442, 220090, 5, 2442, '烦哪~~`', '今天在看别人的文章，讲的是关于高三的事情。然后我一边听着王菲的歌，一边看着那文章，不知道为什么的，就是觉得很伤感，无奈。虽然我还没经历高三，此生我也不会经历，但是我想，受过高三，或者说高考洗礼的人一定很不简单，他们都不是平凡的人。父辈们常常说他们当年上山下乡是多么艰苦，可是岂知一代人有一代人的艰苦，他们上山下乡，而我们，却注定为了学习得付出一生。不愿学习的，他们只能自费出国，或者打工；愿意学习的，却注定一辈子关在书房里，埋在书堆里，因为书是永远也念不完的。我讨厌学习，可是我必须学习，很无奈。我常常觉得自己平静的表面下是一颗汹涌澎湃的心。我以前还在故乡的时候，常常会听到别人夸我说这孩子真会念书，然后我会在别人的面前露出乖孩子般的微笑，可是又有多少人知道我和父母之间的争吵，和房间里我的泪流满面呢？我在国外的时候常常想要像疯子一样地大叫，我想逃离那样的生活。那种生活也许没有高三来得苍白无力，可是生活是无趣的。当所有的尖子生在一起的时候，一切就会变得很可怖。就像有的人说的那样，大学里的学生会是一个训练人的地方，而我的那个“地方”也是这样的一个地方。我的每一天，都让我感到很无趣，很有压力，在这一年里，我真的不曾觉得我的哪一天是彻头彻尾的，是发自内心的快乐。我的每一天，给我的感觉就像是行尸走肉，我的身体像是脱离了灵魂，我不知道自己在做什么。当实力很强的两方相互对抗的时候，必定有一方会倒下。我不愿与人争斗，我倒下了。可是我不知道明年的我是不是要像很多学姐学长那样，屈服在高考的淫威之下，而我，屈服在我的升学考试的淫威之下。放弃理想，放弃友情，放弃快乐，放弃我本来就不多的东西，然后去试着抓住那个叫成绩的东西。我清楚地看到我的同学，那个尖子生中的尖子生，她是我们当中的第一名，可是她比我们当中的任何一个人都要老得早，我还记得她给我发她的照片的时候，我的第一个反应就是，这是你的妈妈吗？这样的事情是不是很可悲，可是这是真的。我们还常常已嘲笑她为乐趣，或者这样有点不对。可是太过于优秀的人不仅会招人嫉妒，还会惹人讨厌，我想我和我最好的朋友是讨厌她的，那个除了读书一无是处的笨女生！我不知道我还要说什么，总而言之，我向所有从高三这条天堂路上走过的人致敬，我想我有一天也还是得成为这样的人，虽然我很不愿意，可是有的事情只有“该做和不该做”，并没有“爱做和不爱做”.', '今天在看别人的文章，讲的是关于高三的事情。然后我一边听着王菲的歌，一边看着那文章，不知道为什么的，就是觉得很伤感，无奈。虽然我还没经历高三，此生我也不会经历，但是我想，受过高三，或者说高考洗礼的人一定很不简单，他们都不是平凡的人。父辈们常常说他们当年上山下乡是多么艰苦，可是岂知一代人有一代人的艰苦，他们上山下乡，而我们，却注定为了学习得付出一生。不愿学习的，他们只能自费出国，或者打工；愿意学习的，却注定一辈子关在书房里，埋在书堆里，因为书是永远也念不完的。我讨厌学习，可是我必须学习，很无奈。我常常觉得自己平静的表面下是一颗汹涌澎湃的心。我以前还在故乡的时候，常常会听到别人夸我说这孩子真会念书，然后我会在别人的面前露出乖孩子般的微笑，可是又有多少人知道我和父母之间的争吵，和房间里我的泪流满面呢？我在国外的时候常常想要像疯子一样地大叫，我想逃离那样的生活。那种生活也许没有高三来得苍白无力，可是生活是无趣的。当所有的尖子生在一起的时候，一切就会变得很可怖。就像有的人说的那样，大学里的学生会是一个训练人的地方，而我的那个“地方”也是这样的一个地方。我的每一天，都让我感到很无趣，很有压力，在这一年里，我真的不曾觉得我的哪一天是彻头彻尾的，是发自内心的快乐。我的每一天，给我的感觉就像是行尸走肉，我的身体像是脱离了灵魂，我不知道自己在做什么。当实力很强的两方相互对抗的时候，必定有一方会倒下。我不愿与人争斗，我倒下了。可是我不知道明年的我是不是要像很多学姐学长那样，屈服在高考的淫威之下，而我，屈服在我的升学考试的淫威之下。放弃理想，放弃友情，放弃快乐，放弃我本来就不多的东西，然后去试着抓住那个叫成绩的东西。我清楚地看到我的同学，那个尖子生中的尖子生，她是我们当中的第一名，可是她比我们当中的任何一个人都要老得早，我还记得她给我发她的照片的时候，我的第一个反应就是，这是你的妈妈吗？这样的事情是不是很可悲，可是这是真的。我们还常常已嘲笑她为乐趣，或者这样有点不对。可是太过于优秀的人不仅会招人嫉妒，还会惹人讨厌，我想我和我最好的朋友是讨厌她的，那个除了读书一无是处的笨女生！我不知道我还要说什么，总而言之，我向所有从高三这条天堂路上走过的人致敬，我想我有一天也还是得成为这样的人，虽然我很不愿意，可是有的事情只有“该做和不该做”，并没有“爱做和不爱做”.', NULL, '2003-12-05 10:43:00', 4, '20031229053219_bbsid_220090_board_5_b03678e0e6.html', '20031229053219');
